import{_ as e,c as t,o as a,aP as s}from"./chunks/framework.BQ2N21Ks.js";const _=JSON.parse('{"title":"npm怎么切换镜像源","description":"","frontmatter":{},"headers":[],"relativePath":"npm/book1_mirror.md","filePath":"npm/book1_mirror.md","lastUpdated":1690561590000}'),r={name:"npm/book1_mirror.md"},o=s('<h1 id="npm怎么切换镜像源" tabindex="-1">npm怎么切换镜像源 <a class="header-anchor" href="#npm怎么切换镜像源" aria-label="Permalink to &quot;npm怎么切换镜像源&quot;">​</a></h1><ol><li><p>首先，可以使用以下命令检查当前的镜像源：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>npm config get registry</span></span></code></pre></div></li><li><p>如果你希望切换到一个国内的镜像源，常用的有淘宝镜像（<a href="https://registry.npm.taobao.org" target="_blank" rel="noreferrer">https://registry.npm.taobao.org</a>）和腾讯镜像（<a href="https://mirrors.cloud.tencent.com/npm%EF%BC%89" target="_blank" rel="noreferrer">https://mirrors.cloud.tencent.com/npm）</a> 等。你可以使用以下命令将镜像源修改为淘宝镜像为例：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>npm config set registry https://registry.npm.taobao.org</span></span></code></pre></div></li><li><p>确认镜像源已经切换成功，可以再次运行以下命令验证：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>npm config get registry</span></span></code></pre></div></li></ol><p>现在，你的 npm 镜像源已经成功切换到了指定的源。在国内使用国内镜像源通常可以提高下载速度和稳定性。如果需要切换回官方源，可以将镜像源修改为 <a href="https://registry.npmjs.org" target="_blank" rel="noreferrer">https://registry.npmjs.org</a>。</p>',3),n=[o];function p(i,l,c,d,m,h){return a(),t("div",null,n)}const b=e(r,[["render",p]]);export{_ as __pageData,b as default};
